const token = $input.first().json.headers['x-wati-token'];
if (!token || token !== 'CrackTesos2026_WH_Token') {
  return [{json: {ok: 'false', result: 'error', mensaje: 'No autorizado'}}];
}
const body = $input.first().json.body;
let phone = (body.phone || '').toString().replace(/[^0-9]/g, '');
if (!phone.startsWith('57') && phone.length === 10) phone = '57' + phone;
if (!phone || phone.length < 10) return [{json: {ok: 'false', result: 'error', mensaje: 'Teléfono inválido'}}];
if (!body.trivia_id) return [{json: {ok: 'false', result: 'error', mensaje: 'trivia_id requerido'}}];
// Aceptar tanto 'A'/'B'/'C' como el texto de la opción (WATI puede enviar cualquiera)
// La resolución A/B/C se hace en 'Calcular Scoring' comparando contra option_a/b/c de la BD
const rawOption = (body.selected_option || '').toString().trim();
if (!rawOption) return [{json: {ok: 'false', result: 'error', mensaje: 'Opción vacía'}}];
return [{json: {ok: 'true', phone, trivia_id: body.trivia_id, selected_option: rawOption}}];

const input = $('Validar').first().json;
const ctx = $input.first().json;

// Verificaciones
if (!ctx.user_id) return [{json: {ok: 'true', result: 'error', mensaje: 'No estás registrado en el Crack Tesos. Por favor regístrate primero.'}}];
if (!ctx.trivia_id) return [{json: {ok: 'true', result: 'error', mensaje: 'Trivia no encontrada.'}}];
if (ctx.existing_response) return [{json: {ok: 'true', result: 'duplicate', nombre: ctx.name, numero_trivia: String(ctx.trivia_number), mensaje: `Ya respondiste la Trivia #${ctx.trivia_number}. Solo cuenta tu primera respuesta. 😊`}}];

// Verificar ventana de tiempo
const now = new Date();
const closesAt = new Date(ctx.closes_at);
if (now > closesAt) {
  return [{json: {ok: 'true', result: 'out_of_time', nombre: ctx.name, numero_trivia: String(ctx.trivia_number), mensaje: `⏰ La Trivia #${ctx.trivia_number} ya cerró. ¡Espera la próxima trivia!`}}];
}

// Calcular tiempo transcurrido
const sentAt = new Date(ctx.sent_at);
const elapsedSeconds = Math.floor((now - sentAt) / 1000);
const elapsedMinutes = elapsedSeconds / 60;

// Resolver opción seleccionada — WATI puede enviar 'A'/'B'/'C' o el texto de la opción
let resolvedOption = input.selected_option.toUpperCase();
if (!['A','B','C'].includes(resolvedOption)) {
  // WATI envió el texto — comparar contra las opciones de la BD
  if (input.selected_option === ctx.option_a) resolvedOption = 'A';
  else if (input.selected_option === ctx.option_b) resolvedOption = 'B';
  else if (input.selected_option === ctx.option_c) resolvedOption = 'C';
  else {
    return [{json: {ok: 'true', result: 'error', nombre: ctx.name, mensaje: 'No pudimos identificar tu respuesta. Intenta de nuevo.'}}];
  }
}

// Verificar respuesta
const isCorrect = resolvedOption === ctx.correct_option;

let baseGoals = 0, speedBonus = 0, speedRange = 0;

if (isCorrect) {
  baseGoals = 100;
  if (elapsedMinutes <= 5)        { speedBonus = 50; speedRange = 1; }
  else if (elapsedMinutes <= 15)  { speedBonus = 35; speedRange = 2; }
  else if (elapsedMinutes <= 30)  { speedBonus = 25; speedRange = 3; }
  else if (elapsedMinutes <= 360) { speedBonus = 15; speedRange = 4; }
  else if (elapsedMinutes <= 1440){ speedBonus = 5;  speedRange = 5; }
}

const totalGoals = baseGoals + speedBonus;
const newTotal = (ctx.total_goals || 0) + totalGoals;

// Mensaje de respuesta
let mensaje;
if (isCorrect) {
  const bonusText = speedBonus > 0 ? ` + ${speedBonus} goles de bono por rapidez` : '';
  mensaje = `⚽ ¡Correcto! Ganaste ${baseGoals} goles base${bonusText}. Total en esta trivia: ${totalGoals} goles. Llevas ${newTotal} goles acumulados.`;
} else {
  mensaje = `❌ Respuesta incorrecta. Esta vez no ganas goles. Llevas ${ctx.total_goals || 0} goles acumulados. ¡Sigue participando!`;
}

return [{json: {
  ok: 'true',
  result: isCorrect ? 'correct' : 'incorrect',
  user_id: ctx.user_id,
  nombre: ctx.name,
  phone: input.phone,
  trivia_id: ctx.trivia_id,
  numero_trivia: String(ctx.trivia_number),
  correct_option: ctx.correct_option,
  selected_option: input.selected_option,
  is_correct: isCorrect ? 'true' : 'false',
  elapsed_seconds: String(elapsedSeconds),
  speed_range: String(speedRange),
  base_goals: String(baseGoals),
  speed_bonus: String(speedBonus),
  total_goals_trivia: String(totalGoals),
  total_accumulated: String(newTotal),
  current_total: String(ctx.total_goals || 0),
  mensaje
}}];

