SELECT '{{ $('Calcular Scoring').first().json.user_id }}', '{{ $('Calcular Scoring').first().json.trivia_id }}', {{ $('Calcular Scoring').first().json.numero_trivia }}, 'trivia_base', {{ $('Calcular Scoring').first().json.base_goals }}, 'Trivia #{{ $('Calcular Scoring').first().json.numero_trivia }} base', '{{ $json.response_id }}', 'system'
WHERE {{ $('Calcular Scoring').first().json.base_goals }} > 0;
